"use client";

import { Check } from "lucide-react";

import { createCompoundComponent } from "@/components/ui/compound";
import { cn } from "@/lib/utils";

import { demoProgressSteps } from "./demo/status";

/**
 * Represents an individual step in the progress tracker.
 * @interface Step
 * @property {string} [label] - Display text for the step
 * @property {"completed" | "current" | "pending"} [status] - Current status of the step
 */
export interface Step {
  label?: string;
  status?: "completed" | "current" | "pending";
}

/**
 * ═══════════════════════════════════════════════════════════════════════════
 * ProgressStepsProps
 * ═══════════════════════════════════════════════════════════════════════════
 *
 * Props for the ProgressSteps component, which displays a visual progress
 * tracker showing sequential steps with completion states.
 */
export interface ProgressStepsProps {
  data?: {
    /** Array of steps to display with their labels and status. */
    steps?: Step[];
  };
}

const ProgressStepsView = ({ data }: ProgressStepsProps) => {
  const resolved: NonNullable<ProgressStepsProps["data"]> = data ?? {
    steps: demoProgressSteps,
  };
  const steps = resolved.steps ?? [];
  return (
    <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-2 bg-card rounded-lg p-4">
      {steps.map((step, index) => {
        const stepStatus = step.status ?? "pending";
        return (
          <div key={index} className="flex items-center gap-2">
            <div className="flex items-center gap-2">
              <div
                className={cn(
                  "flex h-5 w-5 items-center justify-center rounded-full text-xs flex-shrink-0",
                  stepStatus === "completed" && "bg-foreground text-background",
                  stepStatus === "current" && "border-2 border-foreground",
                  stepStatus === "pending" &&
                    "border border-muted-foreground/40"
                )}
              >
                {stepStatus === "completed" && <Check className="h-3 w-3" />}
              </div>
              {step.label && (
                <span
                  className={cn(
                    "text-xs sm:text-sm",
                    stepStatus === "current" && "font-medium",
                    stepStatus === "pending" && "text-muted-foreground"
                  )}
                >
                  {step.label}
                </span>
              )}
            </div>
            {index < steps.length - 1 && (
              <div className="hidden sm:block w-4 h-px bg-border" />
            )}
          </div>
        );
      })}
    </div>
  );
};

export const ProgressSteps = createCompoundComponent(
  ProgressStepsView,
  "ProgressSteps"
);

// Demo data for Status category components
// This file contains sample data used for component previews and documentation

export const demoProgressSteps = [
  { label: "Cart", status: "completed" as const },
  { label: "Shipping", status: "current" as const },
  { label: "Payment", status: "pending" as const },
  { label: "Confirm", status: "pending" as const },
];

export const demoStatusBadge = {
  label: "Processing",
  status: "processing" as const,
};

"use client";

import { createContext, createElement, useContext } from "react";
import type { ComponentType, ImgHTMLAttributes, ReactNode } from "react";

export const RegistryImage = (props: ImgHTMLAttributes<HTMLImageElement>) =>
  createElement("img", props);

export const createCompoundComponent = <Props extends object>(
  View: ComponentType<Props>,
  displayName: string
) => {
  const Context = createContext<Props | null>(null);

  const Content = (overrides: Partial<Props>) => {
    const value = useContext(Context);

    if (!value) {
      throw new Error(
        `${displayName}.Content must be used within ${displayName}`
      );
    }

    return <View {...value} {...overrides} />;
  };

  const Root = ({
    children,
    ...props
  }: Props & {
    children?: ReactNode;
  }) => (
    <Context.Provider value={props as Props}>
      {children ?? <Content />}
    </Context.Provider>
  );

  Root.displayName = displayName;
  Content.displayName = `${displayName}.Content`;

  return Object.assign(Root, { Content });
};
